import conceptContent from "../data/conceptContent";

export async function generateConceptContent(
  conceptName,
  profile = "beginner",
  masteryPct = 0,
  recentScore = null,
  cognitiveLoad = "low",
) {
  const tier = masteryPct < 45 ? "easy" : masteryPct > 65 ? "hard" : "medium";

  // Simulate brief loading delay for UX
  await new Promise((r) => setTimeout(r, 800));

  const conceptData = conceptContent[conceptName];
  if (!conceptData) {
    throw new Error(`No content found for: ${conceptName}`);
  }

  return conceptData[tier];
}
